            { group: 'Developer Infrastructure', items: ['Assistants API (Code execution, Retrieval, Function calling)', 'Embeddings API (Vector database structuring)', 'Fine-tuning capabilities (Training models on bespoke data)', 'Vision API (Image analysis and comprehension)'] }
